public class BellmanFord {

    static class Edge {
        int u, v, weight;
        Edge(int u, int v, int w) { this.u = u; this.v = v; this.weight = w; }
    }

    // Returns shortest distances from source, or null if negative cycle exists
    public static int[] shortestPath(int V, List<Edge> edges, int source) {
        int[] dist = new int[V];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[source] = 0;

        // Relax all edges V-1 times
        for (int i = 0; i < V - 1; i++) {
            for (Edge e : edges) {
                if (dist[e.u] != Integer.MAX_VALUE &&
                    dist[e.u] + e.weight < dist[e.v]) {
                    dist[e.v] = dist[e.u] + e.weight;
                }
            }
        }

        // Check for negative-weight cycles
        for (Edge e : edges) {
            if (dist[e.u] != Integer.MAX_VALUE &&
                dist[e.u] + e.weight < dist[e.v]) {
                return null; // negative cycle detected
            }
        }
        return dist;
    }

    public static void main(String[] args) {
        List<Edge> edges = List.of(
            new Edge(0, 1, -1), new Edge(0, 2, 4),
            new Edge(1, 2, 3),  new Edge(1, 3, 2), new Edge(1, 4, 2),
            new Edge(3, 2, 5),  new Edge(3, 1, 1), new Edge(4, 3, -3)
        );
        int[] dist = shortestPath(5, edges, 0);
        System.out.println(Arrays.toString(dist)); // [0, -1, 2, -2, 1]
    }
}

public class FloydWarshall {

    static final int INF = (int) 1e9;

    public static int[][] allPairsShortestPath(int[][] graph) {
        int V = graph.length;
        int[][] dist = new int[V][V];

        // Initialise distance matrix
        for (int i = 0; i < V; i++)
            for (int j = 0; j < V; j++)
                dist[i][j] = (graph[i][j] == 0 && i != j) ? INF : graph[i][j];

        // Try each vertex k as an intermediate waypoint
        for (int k = 0; k < V; k++) {
            for (int i = 0; i < V; i++) {
                for (int j = 0; j < V; j++) {
                    // Skip if path through k isn't reachable
                    if (dist[i][k] == INF || dist[k][j] == INF) continue;
                    if (dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // Detect negative cycles: dist[i][i] < 0 means negative cycle through i
        for (int i = 0; i < V; i++) {
            if (dist[i][i] < 0) throw new RuntimeException("Negative cycle detected");
        }
        return dist;
    }

    // Transitive closure: is there a path from i to j?
    public static boolean[][] transitiveClosure(boolean[][] adj) {
        int V = adj.length;
        boolean[][] reach = new boolean[V][V];
        for (int i = 0; i < V; i++)
            for (int j = 0; j < V; j++)
                reach[i][j] = adj[i][j] || (i == j);
        for (int k = 0; k < V; k++)
            for (int i = 0; i < V; i++)
                for (int j = 0; j < V; j++)
                    reach[i][j] |= (reach[i][k] && reach[k][j]);
        return reach;
    }

    public static void main(String[] args) {
        int[][] graph = {
            {0,  5, INF, 10},
            {INF,0,  3, INF},
            {INF,INF,0,  1},
            {INF,INF,INF, 0}
        };
        int[][] dist = allPairsShortestPath(graph);
        // dist[0][3] = 9 (0→1→2→3: 5+3+1)
    }
}

public class KruskalMST {

    static class Edge implements Comparable<Edge> {
        int u, v, weight;
        Edge(int u, int v, int w) { this.u = u; this.v = v; this.weight = w; }
        public int compareTo(Edge other) { return this.weight - other.weight; }
    }

    // Union-Find with path compression + union by rank
    static int[] parent, rank;

    static int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]); // path compression
        return parent[x];
    }

    static boolean union(int x, int y) {
        int px = find(x), py = find(y);
        if (px == py) return false; // already connected
        if (rank[px] < rank[py]) { int t = px; px = py; py = t; }
        parent[py] = px;
        if (rank[px] == rank[py]) rank[px]++;
        return true;
    }

    public static List<Edge> kruskal(int V, List<Edge> edges) {
        parent = new int[V];
        rank   = new int[V];
        for (int i = 0; i < V; i++) parent[i] = i;

        Collections.sort(edges);  // sort by weight

        List<Edge> mst = new ArrayList<>();
        int totalWeight = 0;

        for (Edge e : edges) {
            if (union(e.u, e.v)) {   // no cycle → add to MST
                mst.add(e);
                totalWeight += e.weight;
                if (mst.size() == V - 1) break; // MST complete
            }
        }
        return mst; // V-1 edges in MST
    }

    public static void main(String[] args) {
        List<Edge> edges = List.of(
            new Edge(0,1,10), new Edge(0,2,6), new Edge(0,3,5),
            new Edge(1,3,15), new Edge(2,3,4)
        );
        List<Edge> mst = kruskal(4, edges);
        int cost = mst.stream().mapToInt(e -> e.weight).sum();
        System.out.println("MST cost: " + cost); // 19
    }
}

public class PrimsMST {

    public static int primMST(int V, List<int[]>[] adj) {
        // adj[u] = list of [v, weight]
        boolean[] inMST   = new boolean[V];
        int[]     minEdge = new int[V];    // min weight edge to include vertex
        Arrays.fill(minEdge, Integer.MAX_VALUE);
        minEdge[0] = 0;

        // PriorityQueue: [weight, vertex]
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        pq.offer(new int[]{0, 0});

        int totalWeight = 0;

        while (!pq.isEmpty()) {
            int[] curr   = pq.poll();
            int weight   = curr[0];
            int u        = curr[1];

            if (inMST[u]) continue; // already included
            inMST[u] = true;
            totalWeight += weight;

            for (int[] neighbour : adj[u]) {
                int v   = neighbour[0];
                int w   = neighbour[1];
                if (!inMST[v] && w < minEdge[v]) {
                    minEdge[v] = w;
                    pq.offer(new int[]{w, v});
                }
            }
        }
        return totalWeight;
    }

    @SuppressWarnings("unchecked")
    public static void main(String[] args) {
        int V = 5;
        List<int[]>[] adj = new ArrayList[V];
        for (int i = 0; i < V; i++) adj[i] = new ArrayList<>();
        // Add undirected edges (u, v, weight)
        int[][] edges = {{0,1,2},{0,3,6},{1,2,3},{1,3,8},{1,4,5},{2,4,7},{3,4,9}};
        for (int[] e : edges) {
            adj[e[0]].add(new int[]{e[1], e[2]});
            adj[e[1]].add(new int[]{e[0], e[2]});
        }
        System.out.println(primMST(V, adj)); // 16
    }
}

public class CycleDetection {

    // ── Directed graph: DFS with 3-colour marking ──────────────────────────
    static final int WHITE = 0, GRAY = 1, BLACK = 2;

    public static boolean hasCycleDirected(int V, List<Integer>[] adj) {
        int[] color = new int[V]; // all WHITE initially
        for (int i = 0; i < V; i++) {
            if (color[i] == WHITE && dfsCycleDirected(i, adj, color)) return true;
        }
        return false;
    }

    private static boolean dfsCycleDirected(int u, List<Integer>[] adj, int[] color) {
        color[u] = GRAY; // entering — on current DFS path
        for (int v : adj[u]) {
            if (color[v] == GRAY) return true;  // back edge → cycle
            if (color[v] == WHITE && dfsCycleDirected(v, adj, color)) return true;
        }
        color[u] = BLACK; // leaving — fully explored
        return false;
    }

    // ── Undirected graph: DFS tracking parent ─────────────────────────────
    public static boolean hasCycleUndirected(int V, List<Integer>[] adj) {
        boolean[] visited = new boolean[V];
        for (int i = 0; i < V; i++) {
            if (!visited[i] && dfsCycleUndirected(i, -1, adj, visited)) return true;
        }
        return false;
    }

    private static boolean dfsCycleUndirected(int u, int parent, List<Integer>[] adj, boolean[] visited) {
        visited[u] = true;
        for (int v : adj[u]) {
            if (!visited[v]) {
                if (dfsCycleUndirected(v, u, adj, visited)) return true;
            } else if (v != parent) {
                return true; // back edge to non-parent → cycle
            }
        }
        return false;
    }

    // ── Undirected graph: Union-Find (elegant for edge list) ──────────────
    static int[] parent;
    static int find(int x) { return parent[x] == x ? x : (parent[x] = find(parent[x])); }

    public static boolean hasCycleUnionFind(int V, int[][] edges) {
        parent = new int[V];
        for (int i = 0; i < V; i++) parent[i] = i;
        for (int[] e : edges) {
            if (find(e[0]) == find(e[1])) return true; // same component → cycle
            parent[find(e[0])] = find(e[1]); // union
        }
        return false;
    }

    public static void main(String[] args) {
        // Directed cycle: 0→1→2→0
        List<Integer>[] dag = new ArrayList[3];
        for (int i = 0; i < 3; i++) dag[i] = new ArrayList<>();
        dag[0].add(1); dag[1].add(2); dag[2].add(0);
        System.out.println(hasCycleDirected(3, dag)); // true
    }
}
